final:
module RefModule (
    input wire clk,
    input wire rst_n,
    input wire t,
    output reg q
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            q <= 1'b0;
        end else if (t) begin
            q <= ~q;
        end
    end

endmodule
